changeSet.sql:
INSERT INTO clinlims.menu (id, parent_id, presentation_order, element_id, action_url, display_key, is_active)
SELECT nextval('clinlims.menu_seq'),
       (SELECT id FROM clinlims.menu WHERE element_id = 'menu_reports'),
       5, 'menu_reports_environmental', '', 'sideNav.title.environmentalReports', true
WHERE NOT EXISTS (
  SELECT 1 FROM clinlims.menu WHERE element_id = 'menu_reports_environmental'
)
AND EXISTS (
  SELECT 1 FROM clinlims.menu WHERE element_id = 'menu_reports'
);
